import javax.swing.*;
import java.awt.event.*;

public class EventDemo {
 public static void main(String[] args) {
 JFrame frame = new JFrame("Event Demo");
 JButton btn = new JButton("Click");

 // Event handling implementation
 btn.addActionListener(new ActionListener() {
 public void actionPerformed(ActionEvent e) {
 JOptionPane.showMessageDialog(frame, "Button clicked!");
 }
 });

 frame.add(btn);
 frame.setSize(200, 150);
 frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
 frame.setVisible(true);
 }
}

// Model
class CounterModel {
 private int count = 0;

 public void increment() { count++; }
 public int getCount() { return count; }
}

// View
class CounterView {
 private JLabel label;

 public CounterView() {
 JFrame frame = new JFrame("MVC Demo");
 label = new JLabel("Count: 0");
 JButton btn = new JButton("Add");

 frame.setLayout(new FlowLayout());
 frame.add(label);
 frame.add(btn);
 frame.pack();
 frame.setVisible(true);

 // Controller connection
 btn.addActionListener(e -> {
 CounterController.increment();
 updateView(CounterModel.getCount());
 });
 }

 public void updateView(int count) {
 label.setText("Count: " + count);
 }
}

// Controller
class CounterController {
 private static CounterModel model = new CounterModel();

 public static void increment() {
 model.increment();
 }
}

